function uuidv4(){return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g,c=>{const r=Math.random()*16|0,v=c==='x'?r:(r&0x3|0x8);return v.toString(16);});}

const body = $node['1. Receive Resume'].json.body || {};
const binary = $input.item.binary?.data;

const escape = (s='')=>s.replace(/\s+/g,' ').trim().replace(/'/g,"''");

return [{json:{
  applicationId: uuidv4(),
  fileName: binary?.fileName || 'resume.pdf',
  resumeText: escape($json.text),
  jobDescription: escape(body.job_description),
  candidateEmail: escape(body.email),
  jobId: escape(body.jobId || 'DEFAULT'),
  receivedAt: new Date().toISOString()
}}];

