const r=$input.first().json;
const p=$node['3. Prepare Data'].json;

return [{json:{
  applicationId: r?.[0]?.application_id || p.applicationId,
  fileName: p.fileName,
  resumeText: p.resumeText,
  jobDescription: p.jobDescription,
  candidateEmail: p.candidateEmail,
  jobId: p.jobId,
  receivedAt: p.receivedAt
}}];

const raw=$json;
let data;
try{
  let c=raw.choices?.[0]?.message?.content||'';
  c=c.replace(/```json|```/g,'').trim();
  const m=c.match(/\{[\s\S]*\}/);
  data=JSON.parse(m?m[0]:c);
}catch(e){
  data={candidate_name:'Error',score:0,skills_matched:[],missing_skills:[],experience_years:0,education:'Unknown',recommendation:e.message};
}

const id=$node['Merge Data'].json.applicationId;
const score=Math.max(0,Math.min(100,data.score||0));
const status=score>=70?'SHORTLISTED':score>=50?'REVIEW':'REJECTED';

return [{json:{
  applicationId:id,
  candidateName:data.candidate_name,
  score,
  skillsMatched:(data.skills_matched||[]).join(','),
  missingSkills:(data.missing_skills||[]).join(','),
  experienceYears:data.experience_years||0,
  education:data.education||'Unknown',
  recommendation:data.recommendation||'',
  status,
  processedAt:new Date().toISOString()
}}];

parameters.query:
UPDATE applications SET status='{{ $json.status }}', match_score={{ $json.score }}, candidate_name='{{ $json.candidateName }}', skills_matched=string_to_array('{{ $json.skillsMatched }}',','), missing_skills=string_to_array('{{ $json.missingSkills }}',','), experience_years={{ $json.experienceYears }}, education='{{ $json.education }}', recommendation='{{ $json.recommendation }}', processed_at=NOW()
WHERE application_id='{{ $json.applicationId }}'
RETURNING *;
